from fastapi import FastAPI, Request
from fastapi.responses import JSONResponse
from fastapi.exceptions import RequestValidationError
from anthropic import APIStatusError, RateLimitError, APITimeoutError

app = FastAPI()

def error_response(code: str, message: str, status: int, details: dict | None = None) -> JSONResponse:
    body = {"error": {"code": code, "message": message}}
    if details:
        body["error"]["details"] = details
    return JSONResponse(status_code=status, content=body)

# Example error codes and HTTP status mappings:
# "invalid_request"   → 400   (bad input shape)
# "auth_failed"       → 401   (missing / invalid API key)
# "rate_limited"      → 429   (requests-per-minute exceeded)
# "provider_error"    → 502   (Anthropic API returned an error)
# "timeout"           → 504   (agent run exceeded max_seconds)
# "tool_error"        → 422   (a tool function raised an exception)

@app.exception_handler(RequestValidationError)
async def validation_handler(req: Request, exc: RequestValidationError):
    return error_response("invalid_request", "Request body is invalid", 400, {"fields": exc.errors()})

@app.exception_handler(RateLimitError)
async def rate_limit_handler(req: Request, exc: RateLimitError):
    return error_response("rate_limited", "Too many requests", 429)

@app.exception_handler(APITimeoutError)
async def timeout_handler(req: Request, exc: APITimeoutError):
    return error_response("timeout", "Agent run exceeded time limit", 504)

@app.exception_handler(APIStatusError)
async def provider_handler(req: Request, exc: APIStatusError):
    return error_response("provider_error", f"Upstream LLM error: {exc.message}", 502)

import redis, json, hashlib, time
from fastapi import FastAPI, Header
from typing import Optional

app = FastAPI()
r = redis.Redis(host="localhost", port=6379, decode_responses=True)
IDEM_TTL = 86400  # 24 hours

def get_cached_result(key: str) -> dict | None:
    raw = r.get(f"idem:{key}")
    return json.loads(raw) if raw else None

def cache_result(key: str, result: dict) -> None:
    r.set(f"idem:{key}", json.dumps(result), ex=IDEM_TTL)

@app.post("/agent/chat")
async def chat(req: dict, x_idempotency_key: Optional[str] = Header(None)) -> dict:
    if x_idempotency_key:
        cached = get_cached_result(x_idempotency_key)
        if cached:
            return {**cached, "idempotent_replay": True}

    # Run the agent
    result = {"reply": "...", "usage": {"input": 50, "output": 80}}

    if x_idempotency_key:
        cache_result(x_idempotency_key, result)

    return result

from dataclasses import dataclass
from typing import Callable, Any
import json

@dataclass
class ToolDefinition:
    name: str
    description: str
    schema: dict       # JSON Schema for input
    handler: Callable[..., Any]

    def to_anthropic(self) -> dict:
        return {
            "name": self.name,
            "description": self.description,
            "input_schema": self.schema,
        }

# Registry: name → ToolDefinition
REGISTRY: dict[str, ToolDefinition] = {}

def register_tool(name: str, description: str, schema: dict):
    """Decorator that registers a function as a tool."""
    def decorator(fn: Callable) -> Callable:
        REGISTRY[name] = ToolDefinition(name=name, description=description, schema=schema, handler=fn)
        return fn
    return decorator

@register_tool(
    name="search_kb",
    description="Search the knowledge base for an answer.",
    schema={"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]},
)
def search_kb(query: str) -> str:
    return f"KB result for '{query}': see section 3.2 of the user guide."

@register_tool(
    name="get_order_status",
    description="Look up the status of an order by order ID.",
    schema={"type": "object", "properties": {"order_id": {"type": "string"}}, "required": ["order_id"]},
)
def get_order_status(order_id: str) -> str:
    return json.dumps({"order_id": order_id, "status": "shipped", "eta": "2025-07-05"})

def resolve_tools(names: list[str]) -> list[dict]:
    """Return Anthropic tool dicts for the requested names; skip unknowns.""""
    return [REGISTRY[n].to_anthropic() for n in names if n in REGISTRY]

def dispatch_tool(name: str, inputs: dict) -> str:
    if name not in REGISTRY:
        return f"Unknown tool: {name}"
    try:
        result = REGISTRY[name].handler(**inputs)
        return result if isinstance(result, str) else json.dumps(result)
    except Exception as e:
        return f"Tool error: {e}"

