import asyncio, uuid
from fastapi import FastAPI, HTTPException

app = FastAPI()

# Per-job cancellation events
_cancel_flags: dict[str, asyncio.Event] = {}

def is_cancelled(job_id: str) -> bool:
    event = _cancel_flags.get(job_id)
    return event is not None and event.is_set()

async def run_agent_job(job_id: str, prompt: str) -> str:
    _cancel_flags[job_id] = asyncio.Event()
    messages = [{"role": "user", "content": prompt}]

    from anthropic import Anthropic
    client = Anthropic()

    for step in range(20):
        if is_cancelled(job_id):
            return f"[Job {job_id} cancelled at step {step}]"

        response = client.messages.create(
            model="claude-opus-4-8",
            max_tokens=512,
            messages=messages,
        )
        if response.stop_reason == "end_turn":
            return response.content[0].text

        # handle tool_use, append messages …
        await asyncio.sleep(0)  # yield to event loop between iterations

    return "[Max steps reached]"

@app.post("/agent/jobs/{job_id}/cancel")
async def cancel_job(job_id: str) -> dict:
    event = _cancel_flags.get(job_id)
    if event is None:
        raise HTTPException(status_code=404, detail="Job not found")
    event.set()
    return {"job_id": job_id, "status": "cancellation_requested"}
